"use client";

import { cn } from "@/lib/utils";

import { MotionConfig, useReducedMotion } from "motion/react";
import { createContext, useContext } from "react";

interface ReducedMotionProp {
  reducedMotion?: boolean;
}

const ReducedMotionOverrideContext = createContext(false);

function useResolvedReducedMotion(reducedMotion?: boolean) {
  const reducedMotionOverride = useContext(ReducedMotionOverrideContext);
  const prefersReducedMotion = useReducedMotion() ?? false;

  return Boolean(
    reducedMotion || reducedMotionOverride || prefersReducedMotion
  );
}

function ReducedMotionConfig({
  children,
  reducedMotion,
}: ReducedMotionProp & {
  children: import("react").ReactNode;
}) {
  const resolvedReducedMotion = useResolvedReducedMotion(reducedMotion);

  return (
    <MotionConfig reducedMotion={resolvedReducedMotion ? "always" : "user"}>
      {children}
    </MotionConfig>
  );
}

const lightTokens = [
  "[--background:#ffffff]",
  "[--foreground:#111111]",
  "[--primary:#111111]",
  "[--secondary:#646b75]",
  "[--surface-border:#e9edf2]",
  "[--border:#e3e7ec]",
  "[--card:#ffffff]",
  "[--card-foreground:#111111]",
  "[--muted:#f5f7fa]",
  "[--muted-foreground:#6d7480]",
  "[--accent:#f3f5f8]",
  "[--accent-foreground:#111111]",
  "[--input:#e3e7ec]",
  "[--ring:rgba(17,17,17,0.16)]",
  "[--destructive:#dc2626]",
  "[--paper:#fcfcfd]",
  "[--popover-foreground:#111111]",
  "[--brand:#0ea5e9]",
  "[--brand-soft:#bae6fd]",
  "[--shadow-soft:0_18px_38px_-24px_rgba(15,23,42,0.35)]",
];

const aliasTokens = [
  "[--color-background:var(--background)]",
  "[--color-foreground:var(--foreground)]",
  "[--color-primary:var(--primary)]",
  "[--color-secondary:var(--secondary)]",
  "[--color-border:var(--border)]",
  "[--color-card:var(--card)]",
  "[--color-card-foreground:var(--card-foreground)]",
  "[--color-muted:var(--muted)]",
  "[--color-muted-foreground:var(--muted-foreground)]",
  "[--color-accent:var(--accent)]",
  "[--color-accent-foreground:var(--accent-foreground)]",
  "[--color-input:var(--input)]",
  "[--color-ring:var(--ring)]",
  "[--color-destructive:var(--destructive)]",
  "[--color-paper:var(--paper)]",
  "[--color-popover-foreground:var(--popover-foreground)]",
  "[--color-brand:var(--brand)]",
  "[--color-brand-soft:var(--brand-soft)]",
];

const darkTokens = [
  "dark:[--background:#111111]",
  "dark:[--foreground:#f6f3ec]",
  "dark:[--primary:#f6f3ec]",
  "dark:[--secondary:#cbc6bb]",
  "dark:[--surface-border:#2a2a25]",
  "dark:[--border:#2b2a25]",
  "dark:[--card:#111111]",
  "dark:[--card-foreground:#f6f3ec]",
  "dark:[--muted:#171716]",
  "dark:[--muted-foreground:#9a958a]",
  "dark:[--accent:#1a1a18]",
  "dark:[--accent-foreground:#f6f3ec]",
  "dark:[--input:#2b2a25]",
  "dark:[--ring:rgba(246,243,236,0.18)]",
  "dark:[--destructive:#f87171]",
  "dark:[--paper:#171716]",
  "dark:[--popover-foreground:#f6f3ec]",
  "dark:[--brand:#38bdf8]",
  "dark:[--brand-soft:#0c4a6e]",
  "dark:[--shadow-soft:0_20px_44px_-28px_rgba(0,0,0,0.6)]",
];

const registryTheme = [
  ...lightTokens,
  ...aliasTokens,
  ...darkTokens,
].join(" ");

const boxTransition = { type: "spring", stiffness: 500, damping: 30 } as const;
const labelTransition = { duration: 0.2 } as const;
const reducedBoxTransition = { duration: 0.12 } as const;
const reducedLabelTransition = { duration: 0.12 } as const;

function getCheckmarkVariants(reduceMotion: boolean) {
  if (reduceMotion) {
    return {
      checked: {
        pathLength: 1,
        opacity: 1,
        transition: {
          pathLength: { duration: 0.12 },
          opacity: { duration: 0.01 },
        },
      },
      unchecked: {
        pathLength: 0,
        opacity: 1,
        transition: {
          pathLength: { duration: 0.12 },
        },
      },
    } as const;
  }

  return {
    checked: {
      pathLength: 1,
      opacity: 1,
      transition: {
        pathLength: { duration: 0.3, ease: [0.65, 0, 0.35, 1] },
        opacity: { duration: 0.05 },
      },
    },
    unchecked: {
      pathLength: 0,
      opacity: 1,
      transition: {
        pathLength: { duration: 0.25, ease: [0.65, 0, 0.35, 1] },
      },
    },
  } as const;
}

export interface CheckboxProps extends ReducedMotionProp {
  checked?: boolean;
  className?: string;
  defaultChecked?: boolean;
  id?: string;
  label?: string;
  onCheckedChange?: (checked: boolean) => void;
}

function setRef<T>(ref: React.Ref<T> | undefined, value: T) {
  if (typeof ref === "function") {
    ref(value);
    return;
  }

  if (ref) {
    (ref as React.MutableRefObject<T>).current = value;
  }
}

const Checkbox = React.forwardRef<HTMLButtonElement, CheckboxProps>(
  (
    {
      checked,
      className,
      defaultChecked = false,
      id,
      label,
      onCheckedChange,
      reducedMotion,
    },
    ref
  ) => {
    const generatedId = React.useId();
    const buttonRef = React.useRef<HTMLButtonElement | null>(null);
    const labelId = label ? `${id ?? generatedId}-label` : undefined;
    const [internal, setInternal] = React.useState(defaultChecked);
    const isControlled = checked !== undefined;
    const value = isControlled ? checked : internal;
    const reduceMotion = useResolvedReducedMotion(reducedMotion);
    const checkmarkVariants = getCheckmarkVariants(reduceMotion);

    const handleCheckedChange = React.useCallback(
      (nextChecked: boolean) => {
        if (!isControlled) {
          setInternal(nextChecked);
        }

        onCheckedChange?.(nextChecked);
      },
      [isControlled, onCheckedChange]
    );

    return (
      <ReducedMotionConfig reducedMotion={reducedMotion}>
        <div
          className={cn(
            registryTheme,
            "inline-flex select-none items-center gap-3",
            className
          )}
        >
          <CheckboxPrimitive.Root
            checked={value}
            id={id}
            nativeButton
            onCheckedChange={(nextChecked) => {
              handleCheckedChange(nextChecked);
            }}
            render={(rootProps) => {
              const {
                className: rootClassName,
                onAnimationEnd: _onAnimationEnd,
                onAnimationIteration: _onAnimationIteration,
                onAnimationStart: _onAnimationStart,
                onDrag: _onDrag,
                onDragEnd: _onDragEnd,
                onDragEnter: _onDragEnter,
                onDragExit: _onDragExit,
                onDragLeave: _onDragLeave,
                onDragOver: _onDragOver,
                onDragStart: _onDragStart,
                onDrop: _onDrop,
                ref: rootRef,
                ...resolvedRootProps
              } = rootProps;

              return (
                <motion.button
                  {...resolvedRootProps}
                  animate={{
                    backgroundColor: value
                      ? "var(--color-foreground)"
                      : "var(--color-background)",
                    borderColor: value
                      ? "var(--color-foreground)"
                      : "var(--color-border)",
                  }}
                  aria-labelledby={labelId}
                  className={cn(
                    "relative flex h-5 w-5 shrink-0 cursor-pointer items-center justify-center rounded border focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                    rootClassName
                  )}
                  initial={false}
                  ref={(node) => {
                    buttonRef.current = node;
                    setRef(rootRef, node);
                    setRef(ref, node);
                  }}
                  transition={
                    reduceMotion ? reducedBoxTransition : boxTransition
                  }
                  type="button"
                  whileTap={reduceMotion ? undefined : { scale: 0.88 }}
                />
              );
            }}
          >
            <CheckboxPrimitive.Indicator
              keepMounted
              render={(indicatorProps) => {
                const {
                  className: indicatorClassName,
                  children: _children,
                  onAnimationEnd: _onAnimationEnd,
                  onAnimationIteration: _onAnimationIteration,
                  onAnimationStart: _onAnimationStart,
                  onDrag: _onDrag,
                  onDragEnd: _onDragEnd,
                  onDragEnter: _onDragEnter,
                  onDragExit: _onDragExit,
                  onDragLeave: _onDragLeave,
                  onDragOver: _onDragOver,
                  onDragStart: _onDragStart,
                  onDrop: _onDrop,
                  ...resolvedIndicatorProps
                } = indicatorProps;

                return (
                  <motion.svg
                    {...resolvedIndicatorProps}
                    animate={value ? "checked" : "unchecked"}
                    className={cn("h-3.5 w-3.5", indicatorClassName)}
                    fill="none"
                    initial={false}
                    stroke="var(--color-background)"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={3}
                    viewBox="0 0 24 24"
                  >
                    <motion.path
                      d="M5 12.5l4.5 4.5L19 7.5"
                      variants={checkmarkVariants}
                    />
                  </motion.svg>
                );
              }}
            />
          </CheckboxPrimitive.Root>

          {label ? (
            <motion.span
              animate={{ opacity: value ? 0.55 : 1 }}
              className="cursor-pointer text-foreground text-sm"
              id={labelId}
              onClick={() => {
                buttonRef.current?.click();
                buttonRef.current?.focus();
              }}
              transition={
                reduceMotion ? reducedLabelTransition : labelTransition
              }
            >
              {label}
            </motion.span>
          ) : null}
        </div>
      </ReducedMotionConfig>
    );
  }
);

Checkbox.displayName = "Checkbox";

export { Checkbox as checkbox };
export { Checkbox };
